$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-memory-'+[guid]::NewGuid().ToString('N'))
try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$write=Join-Path $root 'scripts\write-project-memory.ps1';$read=Join-Path $root 'scripts\get-project-memory.ps1';$empty=& $read -Root $sandbox -Json;if($empty.Trim() -ne '[]'){throw 'Empty project memory must emit a JSON array.'};$record=(& $write -Kind decision -Title 'Cache policy' -Detail 'Use local cache with explicit invalidation.' -Task 'release hardening' -Root $sandbox -Json|Out-String)|ConvertFrom-Json;if($record.automaticPolicyChange -or !$record.expiresAt -or $record.task -ne 'release hardening'){throw 'Memory record contract failed.'};$items=(& $read -Root $sandbox -Query 'cache' -Json|Out-String)|ConvertFrom-Json;if(@($items).Count -ne 1){throw 'Memory retrieval/search failed.'};$summary=(& $read -Root $sandbox -Summary -Json|Out-String)|ConvertFrom-Json;if($summary.activeRecords -ne 1 -or $summary.policyPromotion -ne 'human-approval-required'){throw 'Memory summary contract failed.'};$rejected=$false;try{& $write -Kind lesson -Title x -Detail 'api_key=secret' -Root $sandbox|Out-Null}catch{$rejected=$true};if(!$rejected){throw 'Secret-looking memory was accepted.'};Write-Host 'Project memory tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
